commonErrors.example:
// JavaScript qui empêche Tab de sortir du menu
menu.addEventListener('keydown', (e) => {
  if (e.key === 'Tab') e.preventDefault();
});

commonErrors.correction:
// Permettre Tab pour sortir, ou gérer cycle avec focus trap approprié
menu.addEventListener('keydown', (e) => {
  if (e.key === 'Escape') {
    closeMenu();
    triggerButton.focus();
  }
  // Laisser Tab fonctionner normalement
});
